import TomSelect from"../../tom-select.js";import{KEY_RETURN}from"../../constants.js";import{getDom}from"../../vanilla.js";import{addEvent}from"../../utils.js";TomSelect.define("dropdown_input",function(){var t=this,o=t.settings.controlInput||'<input type="text" autocomplete="off" class="dropdown-input" />';o=getDom(o),t.settings.controlInput=o,t.settings.shouldOpen=!0,t.hook("after","setup",()=>{t.wrapper.setAttribute("tabindex",t.input.disabled?"-1":t.tabIndex),addEvent(t.wrapper,"keypress",o=>{if(!t.control.contains(o.target)&&!t.dropdown.contains(o.target))switch(o.keyCode){case KEY_RETURN:return void t.onClick(o)}}),t.dropdown.insertBefore(o,t.dropdown.firstChild)})});